import { z } from "zod";

export const IMAGE_STUDIO_SETTINGS_KEY = "image_studio_settings";

export type PromptValidationSeverity = "error" | "warning" | "info";

export type PromptValidationSimilarPattern = {
  pattern: string;
  flags?: string | undefined;
  suggestion: string;
  comment?: string | null;
};

export type PromptAutofixOperation =
  | {
      kind: "replace";
      pattern: string;
      flags?: string | undefined;
      replacement: string;
      comment?: string | null;
    }
  | {
      kind: "params_json";
      comment?: string | null;
    };

export type PromptAutofixConfig = {
  enabled: boolean;
  operations: PromptAutofixOperation[];
};

export type PromptValidationRule =
  | {
      kind: "regex";
      id: string;
      enabled: boolean;
      severity: PromptValidationSeverity;
      title: string;
      description: string | null;
      pattern: string;
      flags: string;
      message: string;
      similar: PromptValidationSimilarPattern[];
      autofix?: PromptAutofixConfig | undefined;
    }
  | {
      kind: "params_object";
      id: string;
      enabled: boolean;
      severity: PromptValidationSeverity;
      title: string;
      description: string | null;
      message: string;
      similar: PromptValidationSimilarPattern[];
      autofix?: PromptAutofixConfig | undefined;
    };

export type PromptValidationSettings = {
  enabled: boolean;
  rules: PromptValidationRule[];
  learnedRules?: PromptValidationRule[];
};

export const defaultPromptValidationRules: PromptValidationRule[] = [
  {
    kind: "params_object",
    id: "params.object",
    enabled: true,
    severity: "error",
    title: "Params block",
    description:
      "Required for programmatic extraction. The params object must be JSON-parseable (quoted keys/strings).",
    message: "Prompt must include a valid `params = { ... }` object for extraction.",
    similar: [
      { pattern: "param\\s*=\\s*\\{", flags: "i", suggestion: "Use `params = {` (plural) instead of `param = {`.", comment: null },
      { pattern: "params\\s*:\\s*\\{", flags: "i", suggestion: "Use `params = {` (assignment) instead of `params: {`.", comment: null },
      { pattern: "parameters\\s*=\\s*\\{", flags: "i", suggestion: "Use `params = {` instead of `parameters = {`.", comment: null },
    ],
    autofix: {
      enabled: true,
      operations: [
        { kind: "replace", pattern: "\\bparam\\s*[:=]\\s*\\{", flags: "i", replacement: "params = {", comment: null },
        { kind: "replace", pattern: "\\bparameters\\s*[:=]\\s*\\{", flags: "i", replacement: "params = {", comment: null },
        { kind: "replace", pattern: "\\bparams\\s*[:=]\\s*\\{", flags: "i", replacement: "params = {", comment: "Normalizes casing/spaces so extraction can find `params = {`." },
        { kind: "params_json", comment: "Attempts to convert the params object into strict JSON (quoted keys/strings)." },
      ],
    },
  },
  {
    kind: "regex",
    id: "section.role",
    enabled: true,
    severity: "warning",
    title: "ROLE section",
    description: "Helps keep prompts consistent and readable.",
    pattern: "^##\\s+ROLE\\b",
    flags: "mi",
    message: "Missing `## ROLE` section heading.",
    similar: [
      { pattern: "^#+\\s*Role\\b", flags: "mi", suggestion: "Rename to `## ROLE`.", comment: null },
      { pattern: "^##\\s*ROL\\b", flags: "mi", suggestion: "Fix typo to `## ROLE`.", comment: null },
    ],
    autofix: {
      enabled: true,
      operations: [
        { kind: "replace", pattern: "^#+\\s*role\\b.*$", flags: "mi", replacement: "## ROLE", comment: null },
        { kind: "replace", pattern: "^#+\\s*rol\\b.*$", flags: "mi", replacement: "## ROLE", comment: null },
      ],
    },
  },
  {
    kind: "regex",
    id: "section.non_negotiable_goal",
    enabled: true,
    severity: "warning",
    title: "NON-NEGOTIABLE GOAL section",
    description: "Encouraged structure for strict editing prompts.",
    pattern: "^##\\s+NON-NEGOTIABLE\\s+GOAL\\b",
    flags: "mi",
    message: "Missing `## NON-NEGOTIABLE GOAL` section heading.",
    similar: [
      { pattern: "^##\\s+NON\\s*NEGOTIABLE\\s+GOAL\\b", flags: "mi", suggestion: "Use hyphenated `## NON-NEGOTIABLE GOAL`.", comment: null },
      { pattern: "^#+\\s*Non[-\\s]?negotiable\\b", flags: "mi", suggestion: "Rename to `## NON-NEGOTIABLE GOAL`.", comment: null },
    ],
    autofix: {
      enabled: true,
      operations: [
        { kind: "replace", pattern: "^#+\\s*non\\s*negotiable\\s+goal\\b.*$", flags: "mi", replacement: "## NON-NEGOTIABLE GOAL", comment: null },
        { kind: "replace", pattern: "^#+\\s*non[-\\s]?negotiable\\b.*$", flags: "mi", replacement: "## NON-NEGOTIABLE GOAL", comment: null },
      ],
    },
  },
  {
    kind: "regex",
    id: "section.params",
    enabled: true,
    severity: "warning",
    title: "PARAMS section",
    description: "Expected to wrap the params block so it’s easy to find.",
    pattern: "^##\\s+PARAMS\\b",
    flags: "mi",
    message: "Missing `## PARAMS` section heading.",
    similar: [
      { pattern: "^##\\s*PARAM\\b", flags: "mi", suggestion: "Rename to `## PARAMS`.", comment: null },
      { pattern: "^#+\\s*Params\\b", flags: "mi", suggestion: "Rename to `## PARAMS`.", comment: null },
    ],
    autofix: {
      enabled: true,
      operations: [
        { kind: "replace", pattern: "^#+\\s*param\\b.*$", flags: "mi", replacement: "## PARAMS", comment: null },
        { kind: "replace", pattern: "^#+\\s*params\\b.*$", flags: "mi", replacement: "## PARAMS", comment: null },
      ],
    },
  },
  {
    kind: "regex",
    id: "section.final_qa",
    enabled: true,
    severity: "info",
    title: "FINAL QA section",
    description: "Optional, but helps ensure the prompt includes a clear QA checklist.",
    pattern: "^##\\s+FINAL\\s+QA\\b",
    flags: "mi",
    message: "Missing `## FINAL QA` section heading.",
    similar: [
      { pattern: "^#+\\s*QA\\b", flags: "mi", suggestion: "Rename to `## FINAL QA`.", comment: null },
    ],
    autofix: {
      enabled: true,
      operations: [
        { kind: "replace", pattern: "^#+\\s*qa\\b.*$", flags: "mi", replacement: "## FINAL QA", comment: null },
      ],
    },
  },
];

export type ImageStudioSettings = {
  version: 1;
  promptValidation: PromptValidationSettings;
  promptExtraction: {
    mode: "programmatic" | "gpt";
    gpt: {
      model: string;
      temperature: number | null;
      top_p: number | null;
      max_output_tokens: number | null;
    };
  };
  uiExtractor: {
    mode: "heuristic" | "ai" | "both";
    model: string;
    temperature: number | null;
    max_output_tokens: number | null;
  };
  targetAi: {
    provider: "openai";
    openai: {
      api: "responses" | "images";
      model: string;
      temperature: number | null;
      top_p: number | null;
      max_output_tokens: number | null;
      presence_penalty: number | null;
      frequency_penalty: number | null;
      seed: number | null;
      user: string | null;
      stream: boolean;
      reasoning_effort: "low" | "medium" | "high" | null;
      response_format: "text" | "json" | null;
      tool_choice: "auto" | "none" | null;
      image: {
        size: string | null;
        quality: "standard" | "high" | null;
        background: "transparent" | "white" | null;
        format: "png" | "jpeg" | null;
        n: number | null;
      };
      advanced_overrides: Record<string, any> | null;
    };
  };
};

export const defaultImageStudioSettings: ImageStudioSettings = {
  version: 1,
  promptValidation: {
    enabled: true,
    rules: defaultPromptValidationRules,
    learnedRules: [],
  },
  promptExtraction: {
    mode: "programmatic",
    gpt: {
      model: "gpt-4o-mini",
      temperature: null,
      top_p: null,
      max_output_tokens: null,
    },
  },
  uiExtractor: {
    mode: "heuristic",
    model: "gpt-4o-mini",
    temperature: 0.2,
    max_output_tokens: 800,
  },
  targetAi: {
    provider: "openai",
    openai: {
      api: "images",
      model: "gpt-image-1",
      temperature: null,
      top_p: null,
      max_output_tokens: null,
      presence_penalty: null,
      frequency_penalty: null,
      seed: null,
      user: null,
      stream: false,
      reasoning_effort: null,
      response_format: "text",
      tool_choice: null,
      image: {
        size: null,
        quality: null,
        background: null,
        format: "png",
        n: 1,
      },
      advanced_overrides: null,
    },
  },
};

const finiteNumberOrNull = z.number().finite().nullable().optional().default(null);
const intOrNull = z.number().int().nullable().optional().default(null);
const nonEmptyStringOrNull = z.string().trim().min(1).nullable().optional().default(null);

const promptValidationSeveritySchema = z.enum(["error", "warning", "info"]);
const promptValidationSimilarSchema: z.ZodType<PromptValidationSimilarPattern> = z
  .object({
    pattern: z.string().trim().min(1),
    flags: z.string().trim().optional(),
    suggestion: z.string().trim().min(1),
    comment: z.string().trim().min(1).nullable().optional().default(null),
  })
  .strict();

const promptAutofixOperationSchema: z.ZodType<PromptAutofixOperation> = z.discriminatedUnion("kind", [
  z
    .object({
      kind: z.literal("replace"),
      pattern: z.string().trim().min(1),
      flags: z.string().trim().optional(),
      replacement: z.string(),
      comment: z.string().trim().min(1).nullable().optional().default(null),
    })
    .strict(),
  z
    .object({
      kind: z.literal("params_json"),
      comment: z.string().trim().min(1).nullable().optional().default(null),
    })
    .strict(),
]);

const promptAutofixSchema: z.ZodType<PromptAutofixConfig> = z
  .object({
    enabled: z.boolean().optional().default(true),
    operations: z.array(promptAutofixOperationSchema).optional().default([]),
  })
  .strict();

const promptValidationRuleSchema: z.ZodType<PromptValidationRule> = z.discriminatedUnion("kind", [
  z
    .object({
      kind: z.literal("regex"),
      id: z.string().trim().min(1),
      enabled: z.boolean().optional().default(true),
      severity: promptValidationSeveritySchema.optional().default("warning"),
      title: z.string().trim().min(1),
      description: z.string().trim().min(1).nullable().optional().default(null),
      pattern: z.string().trim().min(1),
      flags: z.string().trim().optional().default("mi"),
      message: z.string().trim().min(1),
      similar: z.array(promptValidationSimilarSchema).optional().default([]),
      autofix: promptAutofixSchema.optional().default({ enabled: true, operations: [] }),
    })
    .strict(),
  z
    .object({
      kind: z.literal("params_object"),
      id: z.string().trim().min(1),
      enabled: z.boolean().optional().default(true),
      severity: promptValidationSeveritySchema.optional().default("error"),
      title: z.string().trim().min(1),
      description: z.string().trim().min(1).nullable().optional().default(null),
      message: z.string().trim().min(1),
      similar: z.array(promptValidationSimilarSchema).optional().default([]),
      autofix: promptAutofixSchema.optional().default({ enabled: true, operations: [] }),
    })
    .strict(),
]);

const promptValidationSettingsSchema: z.ZodType<PromptValidationSettings> = z
  .object({
    enabled: z.boolean().optional().default(defaultImageStudioSettings.promptValidation.enabled),
    rules: z.array(promptValidationRuleSchema).optional().default(defaultImageStudioSettings.promptValidation.rules),
    learnedRules: z.array(promptValidationRuleSchema).optional().default([]),
  })
  .strict();

const imageStudioSettingsSchema: z.ZodType<ImageStudioSettings> = z
  .object({
    version: z.literal(1).optional().default(1),
    promptValidation: promptValidationSettingsSchema.optional().default(defaultImageStudioSettings.promptValidation),
    promptExtraction: z
      .object({
        mode: z.enum(["programmatic", "gpt"]).optional().default("programmatic"),
        gpt: z
          .object({
            model: z.string().trim().min(1).optional().default(defaultImageStudioSettings.promptExtraction.gpt.model),
            temperature: finiteNumberOrNull,
            top_p: finiteNumberOrNull,
            max_output_tokens: intOrNull,
          })
          .optional()
          .default(defaultImageStudioSettings.promptExtraction.gpt),
      })
      .optional()
      .default(defaultImageStudioSettings.promptExtraction),
    uiExtractor: z
      .object({
        mode: z.enum(["heuristic", "ai", "both"]).optional().default(defaultImageStudioSettings.uiExtractor.mode),
        model: z.string().trim().min(1).optional().default(defaultImageStudioSettings.uiExtractor.model),
        temperature: finiteNumberOrNull,
        max_output_tokens: intOrNull,
      })
      .optional()
      .default(defaultImageStudioSettings.uiExtractor),
    targetAi: z
      .object({
        provider: z.literal("openai").optional().default("openai"),
        openai: z
          .object({
            api: z.enum(["responses", "images"]).optional().default(defaultImageStudioSettings.targetAi.openai.api),
            model: z.string().trim().min(1).optional().default(defaultImageStudioSettings.targetAi.openai.model),
            temperature: finiteNumberOrNull,
            top_p: finiteNumberOrNull,
            max_output_tokens: intOrNull,
            presence_penalty: finiteNumberOrNull,
            frequency_penalty: finiteNumberOrNull,
            seed: intOrNull,
            user: nonEmptyStringOrNull,
            stream: z.boolean().optional().default(defaultImageStudioSettings.targetAi.openai.stream),
            reasoning_effort: z.enum(["low", "medium", "high"]).nullable().optional().default(null),
            response_format: z.enum(["text", "json"]).nullable().optional().default(defaultImageStudioSettings.targetAi.openai.response_format),
            tool_choice: z.enum(["auto", "none"]).nullable().optional().default(null),
            image: z
              .object({
                size: nonEmptyStringOrNull,
                quality: z.enum(["standard", "high"]).nullable().optional().default(null),
                background: z.enum(["transparent", "white"]).nullable().optional().default(null),
                format: z.enum(["png", "jpeg"]).nullable().optional().default(defaultImageStudioSettings.targetAi.openai.image.format),
                n: z.number().int().min(1).nullable().optional().default(defaultImageStudioSettings.targetAi.openai.image.n),
              })
              .optional()
              .default(defaultImageStudioSettings.targetAi.openai.image),
            advanced_overrides: z.record(z.string(), z.unknown()).nullable().optional().default(null),
          })
          .optional()
          .default(defaultImageStudioSettings.targetAi.openai),
      })
      .optional()
      .default(defaultImageStudioSettings.targetAi),
  })
  .strict();

export function parseImageStudioSettings(raw: string | null | undefined): ImageStudioSettings {
  if (!raw) return defaultImageStudioSettings;
  try {
    const parsed = JSON.parse(raw) as unknown;
    const result = imageStudioSettingsSchema.safeParse(parsed);
    if (!result.success) return defaultImageStudioSettings;

    const rawRules = (parsed && typeof parsed === "object" && !Array.isArray(parsed))
      ? (parsed as Record<string, unknown>)?.promptValidation
      : null;
    const rawRulesArray =
      rawRules && typeof rawRules === "object" && !Array.isArray(rawRules)
        ? (rawRules as Record<string, unknown>)?.rules
        : null;
    const hadAutofixInStorage = Array.isArray(rawRulesArray)
      ? rawRulesArray.some((rule: unknown) => Boolean(rule) && typeof rule === "object" && "autofix" in (rule as Record<string, unknown>))
      : false;

    if (hadAutofixInStorage) return result.data;

    const defaultById = new Map(defaultPromptValidationRules.map((rule: PromptValidationRule) => [rule.id, rule]));
    const mergedRules = result.data.promptValidation.rules.map((rule: PromptValidationRule) => {
      const defaults = defaultById.get(rule.id);
      if (!defaults?.autofix || defaults.autofix.operations.length === 0) return rule;
      const needsAutofix =
        !rule.autofix ||
        !Array.isArray(rule.autofix.operations) ||
        rule.autofix.operations.length === 0;
      return needsAutofix ? { ...rule, autofix: defaults.autofix } : rule;
    });

    return {
      ...result.data,
      promptValidation: {
        ...result.data.promptValidation,
        rules: mergedRules,
        learnedRules: result.data.promptValidation.learnedRules ?? [],
      },
    };
  } catch {
    return defaultImageStudioSettings;
  }
}

export function parsePromptValidationRules(raw: string): { ok: true; rules: PromptValidationRule[] } | { ok: false; error: string } {
  try {
    const parsed = JSON.parse(raw) as unknown;
    const result = z.array(promptValidationRuleSchema).safeParse(parsed);
    if (result.success) {
      const hadAutofix = Array.isArray(parsed)
        ? parsed.some((rule: unknown) => Boolean(rule) && typeof rule === "object" && "autofix" in (rule as Record<string, unknown>))
        : false;
      if (hadAutofix) return { ok: true, rules: result.data };

      const defaultById = new Map(defaultPromptValidationRules.map((rule: PromptValidationRule) => [rule.id, rule]));
      const mergedRules = result.data.map((rule: PromptValidationRule) => {
        const defaults = defaultById.get(rule.id);
        if (!defaults?.autofix || defaults.autofix.operations.length === 0) return rule;
        const needsAutofix =
          !rule.autofix ||
          !Array.isArray(rule.autofix.operations) ||
          rule.autofix.operations.length === 0;
        return needsAutofix ? { ...rule, autofix: defaults.autofix } : rule;
      });

      return { ok: true, rules: mergedRules };
    }
    return { ok: false, error: "Invalid rules shape. Expected an array of rule objects." };
  } catch {
    return { ok: false, error: "Invalid JSON." };
  }
}

"use client";

import type { Language } from "@/shared/types/internationalization";
import { zodResolver } from "@hookform/resolvers/zod";
import { useRouter } from "next/navigation";
import {
  createContext,
  useContext,
  useState,
  BaseSyntheticEvent,
  useRef,
  useEffect,
} from "react";
import { useQueryClient } from "@tanstack/react-query";
import { useToast } from "@/shared/ui";
import {
  UseFormRegister,
  UseFormSetValue,
  UseFormGetValues,
  FieldErrors,
  FormProvider,
  useForm,
  Resolver,
} from "react-hook-form";

import type {
  CatalogRecord,
  ProductWithImages,
  PriceGroupWithDetails,
  ProductFormData,
  ProductDraft,
} from "@/features/products/types";
import type { ImageFileSelection } from "@/shared/types/files";
import type { ProductCategory, ProductTag, ProductParameter, ProductParameterValue, Producer } from "@/features/products/types";
import {
  ProductImageSlot,
} from "@/features/products/types/products-ui";
import {
  productCreateSchema,
  productUpdateSchema,
} from "@/features/products/validations";

import { useProductImages } from "@/features/products/hooks/useProductImages";
import { useProductMetadata } from "@/features/products/hooks/useProductMetadata";
import { delay } from "@/shared/utils";
import { useCreateProductMutation, useUpdateProductMutation } from "@/features/products/hooks/useProductData";

export interface ProductFormContextType {
  register: UseFormRegister<ProductFormData>;
  handleSubmit: (e?: BaseSyntheticEvent) => Promise<void>;
  errors: FieldErrors<ProductFormData>;
  setValue: UseFormSetValue<ProductFormData>;
  getValues: UseFormGetValues<ProductFormData>;
  imageSlots: (ProductImageSlot | null)[];
  imageLinks: string[];
  imageBase64s: string[];
  uploading: boolean;
  uploadError: string | null;
  uploadSuccess: boolean;
  showFileManager: boolean;
  setShowFileManager: (show: boolean) => void;
  handleSlotImageChange: (file: File | null, index: number) => void;
  handleSlotFileSelect: (file: ImageFileSelection | null, index: number) => void;
  handleSlotDisconnectImage: (index: number) => Promise<void>;
  handleMultiImageChange: (files: File[]) => void;
  handleMultiFileSelect: (files: ImageFileSelection[]) => void;
  swapImageSlots: (fromIndex: number, toIndex: number) => void;
  setImageLinkAt: (index: number, value: string) => void;
  setImageBase64At: (index: number, value: string) => void;
  setImagesReordering: (reordering: boolean) => void;
  catalogs: CatalogRecord[];
  catalogsLoading: boolean;
  catalogsError: string | null;
  selectedCatalogIds: string[];
  toggleCatalog: (catalogId: string) => void;
  categories: ProductCategory[];
  categoriesLoading: boolean;
  selectedCategoryId: string | null;
  setCategoryId: (categoryId: string | null) => void;
  tags: ProductTag[];
  tagsLoading: boolean;
  selectedTagIds: string[];
  toggleTag: (tagId: string) => void;
  producers: Producer[];
  producersLoading: boolean;
  selectedProducerIds: string[];
  toggleProducer: (producerId: string) => void;
  selectedNoteIds: string[];
  toggleNote: (noteId: string) => void;
  removeNote: (noteId: string) => void;
  parameters: ProductParameter[];
  parametersLoading: boolean;
  parameterValues: ProductParameterValue[];
  addParameterValue: () => void;
  updateParameterId: (index: number, parameterId: string) => void;
  updateParameterValue: (index: number, value: string) => void;
  removeParameterValue: (index: number) => void;
  filteredLanguages: Language[];
  filteredPriceGroups: PriceGroupWithDetails[];
  generationError: string | null;
  setGenerationError: (error: string | null) => void;
  product?: ProductWithImages | undefined;
}

export const ProductFormContext = createContext<ProductFormContextType | null>(
  null
);

export const useProductFormContext = (): ProductFormContextType => {
  const context = useContext(ProductFormContext);
  if (!context) {
    throw new Error(
      "useProductFormContext must be used within a ProductFormProvider"
    );
  }
  return context;
};

// This context provides a centralized place for managing the state and logic of the product form.
// It handles form data, image uploads, and communication with the API.
export function ProductFormProvider({
  children,
  product,
  draft,
  onSuccess,
  onEditSave,
  requireSku,
  initialSku,
  initialCatalogId,
}: {
  children: React.ReactNode;
  product?: ProductWithImages | undefined;
  draft?: ProductDraft | null | undefined;
  onSuccess?: ((info?: { queued?: boolean }) => void) | undefined;
  onEditSave?: ((saved: ProductWithImages) => void) | undefined;
  requireSku?: boolean | undefined;
  initialSku?: string | undefined;
  initialCatalogId?: string | undefined;
}): React.ReactNode {
  // product: edit mode -> update schema
  // requireSku: create mode -> create schema; draft mode can allow update schema (SKU optional)
  const formSchema = product || !requireSku ? productUpdateSchema : productCreateSchema;
  const methods = useForm<ProductFormData>({
    resolver: zodResolver(formSchema) as Resolver<ProductFormData>,
    defaultValues: {
      name_en: product?.name_en || draft?.name_en || "",
      name_pl: product?.name_pl || draft?.name_pl || "",
      name_de: product?.name_de || draft?.name_de || "",
      price: product?.price ?? draft?.price ?? 0,
      sku: product?.sku || initialSku || draft?.sku || "",
      defaultPriceGroupId:
        product?.defaultPriceGroupId ?? draft?.defaultPriceGroupId ?? undefined,
      baseProductId: product?.baseProductId ?? draft?.baseProductId ?? undefined,
      ean: product?.ean || draft?.ean || "",
      gtin: product?.gtin || draft?.gtin || "",
      asin: product?.asin || draft?.asin || "",
      description_en: product?.description_en || draft?.description_en || "",
      description_pl: product?.description_pl || draft?.description_pl || "",
      description_de: product?.description_de || draft?.description_de || "",
      supplierName: product?.supplierName || draft?.supplierName || "",
      supplierLink: product?.supplierLink || draft?.supplierLink || "",
      priceComment: product?.priceComment || draft?.priceComment || "",
      stock: product?.stock ?? draft?.stock ?? 0,
      sizeLength: product?.sizeLength ?? draft?.sizeLength ?? 0,
      sizeWidth: product?.sizeWidth ?? draft?.sizeWidth ?? 0,
      weight: product?.weight ?? draft?.weight ?? 0,
      length: product?.length ?? draft?.length ?? 0,
    },
  });
  const {
    register,
    formState: { errors },
    setValue,
    getValues,
  } = methods;
  const { toast } = useToast();
  const router = useRouter();
  const queryClient = useQueryClient();
  const [uploadError, setUploadError] = useState<string | null>(null);
  const [uploadSuccess, setUploadSuccess] = useState(false);
  const successTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const [generationError, setGenerationError] = useState<string | null>(null);

  const createMutation = useCreateProductMutation();
  const updateMutation = useUpdateProductMutation();

  const {
    imageSlots,
    imageLinks,
    imageBase64s,
    showFileManager,
    setShowFileManager,
    handleSlotImageChange,
    handleSlotFileSelect,
    handleSlotDisconnectImage,
    handleMultiImageChange,
    handleMultiFileSelect,
    swapImageSlots,
    setImageLinkAt,
    setImageBase64At,
    refreshFromProduct: refreshImages,
    setImagesReordering,
  } = useProductImages(product, draft?.imageLinks);

  const {
    catalogs,
    catalogsLoading,
    catalogsError,
    selectedCatalogIds,
    toggleCatalog,
    categories,
    categoriesLoading,
    selectedCategoryId,
    setCategoryId,
    tags,
    tagsLoading,
    selectedTagIds,
    toggleTag,
    producers,
    producersLoading,
    selectedProducerIds,
    toggleProducer,
    parameters,
    parametersLoading,
    filteredLanguages,
    filteredPriceGroups,
  } = useProductMetadata({
    product,
    initialCatalogId,
    initialCatalogIds:
      draft?.catalogIds && draft.catalogIds.length > 0
        ? draft.catalogIds
        : initialCatalogId
          ? [initialCatalogId]
          : undefined,
    initialCategoryId: draft?.categoryId ?? null,
    initialTagIds: draft?.tagIds,
    setValue,
    getValues,
  });

  const [selectedNoteIds, setSelectedNoteIds] = useState<string[]>(
    () => (Array.isArray(product?.noteIds) ? product.noteIds : [])
  );

  useEffect(() => {
    setSelectedNoteIds(Array.isArray(product?.noteIds) ? product.noteIds : []);
  }, [product?.id, product?.noteIds]);

  const toggleNote = (noteId: string): void => {
    const id = noteId.trim();
    if (!id) return;
    setSelectedNoteIds((prev: string[]) =>
      prev.includes(id) ? prev.filter((n: string) => n !== id) : [...prev, id]
    );
  };

  const removeNote = (noteId: string): void => {
    const id = noteId.trim();
    if (!id) return;
    setSelectedNoteIds((prev: string[]) => prev.filter((n: string) => n !== id));
  };

  const normalizeParameterValues = (
    input?: ProductParameterValue[] | null
  ): ProductParameterValue[] => {
    if (!Array.isArray(input)) return [];
    return input.map((entry: ProductParameterValue) => ({
      parameterId: typeof entry?.parameterId === "string" ? entry.parameterId : "",
      value: typeof entry?.value === "string" ? entry.value : "",
    }));
  };

  const [parameterValues, setParameterValues] = useState<ProductParameterValue[]>(
    () => normalizeParameterValues(product?.parameters ?? draft?.parameters ?? [])
  );

  useEffect(() => {
    setParameterValues(normalizeParameterValues(product?.parameters ?? draft?.parameters ?? []));
  }, [product?.id, draft?.id, product?.parameters, draft?.parameters]);

  useEffect((): (() => void) => {
    return (): void => {
      if (successTimerRef.current) {
        clearTimeout(successTimerRef.current);
      }
    };
  }, []);

  const onSubmit = async (data: ProductFormData): Promise<void> => {
    const skuValue = typeof data.sku === "string" ? data.sku.trim() : "";
    const hasTempImages = imageSlots.some((slot: ProductImageSlot | null): boolean => {
      if (!slot) return false;
      if (slot.type === "file") return true;
      return slot.previewUrl.startsWith("/uploads/products/temp/");
    });

    if (!skuValue && hasTempImages) {
      const shouldContinue = window.confirm(
        "This product has images without an SKU. They will stay in the temporary folder until you set an SKU. Continue?"
      );
      if (!shouldContinue) {
        return;
      }
    }

    setUploadError(null);
    setUploadSuccess(false);

    const formData = new FormData();
    Object.entries(data).forEach(([key, value]: [string, unknown]): void => {
      if (value !== null && value !== undefined) {
        if (typeof value === "object") {
          formData.append(key, JSON.stringify(value));
        } else if (typeof value === "string") {
          formData.append(key, value);
        } else {
          formData.append(key, String(value as number | boolean));
        }
      }
    });
    const normalizedLinks = imageLinks.map((link: string): string => link.trim());
    formData.append("imageLinks", JSON.stringify(normalizedLinks));
    const normalizedBase64s = imageBase64s.map((link: string): string => link.trim());
    formData.append("imageBase64s", JSON.stringify(normalizedBase64s));

    // Process image slots
    imageSlots.forEach((slot: ProductImageSlot | null): void => {
      if (slot?.type === 'file') {
        formData.append("images", slot.data); // Append actual File object
      } else if (slot?.type === 'existing') {
        formData.append("imageFileIds", slot.data.id); // Append existing ImageFile ID
      }
    });
    selectedCatalogIds.forEach((catalogId: string): void => {
      formData.append("catalogIds", catalogId);
    });
    if (selectedCategoryId) {
      formData.append("categoryId", selectedCategoryId);
    } else {
      // Ensure update mode can clear the category.
      formData.append("categoryId", "");
    }
    selectedTagIds.forEach((tagId: string): void => {
      formData.append("tagIds", tagId);
    });
    selectedProducerIds.forEach((producerId: string): void => {
      formData.append("producerIds", producerId);
    });
    if (selectedProducerIds.length === 0) {
      // Ensure update mode can clear previously assigned producers.
      formData.append("producerIds", "");
    }
    selectedNoteIds.forEach((noteId: string): void => {
      formData.append("noteIds", noteId);
    });
    if (selectedNoteIds.length === 0) {
      // Ensure update mode can clear previously assigned note links.
      formData.append("noteIds", "");
    }
    const normalizedParameters = parameterValues
      .map((entry: ProductParameterValue): { parameterId: string | undefined; value: string } => ({
        parameterId: entry.parameterId?.trim(),
        value: typeof entry.value === "string" ? entry.value.trim() : "",
      }))
      .filter((entry: { parameterId: string | undefined; value: string }): boolean => !!entry.parameterId);
    formData.append("parameters", JSON.stringify(normalizedParameters));

    try {
      const savedProduct = product
        ? await updateMutation.mutateAsync({ id: product.id, data: formData })
        : await createMutation.mutateAsync(formData);

      const isQueued = savedProduct == null;

      if (isQueued) {
        if (product) {
          onSuccess?.({ queued: true });
        } else {
          onSuccess?.({ queued: true });
        }
        return;
      }

      // Small delay to ensure DB consistency before refetch
      await delay(500);

      // Invalidate both products list and count queries
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: ["products"] }),
        queryClient.invalidateQueries({ queryKey: ["products-count"] }),
      ]);

      if (!product) {
        onSuccess?.();
      } else {
        refreshImages(savedProduct as ProductWithImages);
        setUploadSuccess(true);
        if (successTimerRef.current) {
          clearTimeout(successTimerRef.current);
        }
        successTimerRef.current = setTimeout(() => {
          setUploadSuccess(false);
        }, 3000);
        // Product edit modal flow passes `onSuccess` which already shows a toast and closes the modal.
        // Edit page flow doesn't pass `onSuccess`, so we show a toast here.
        if (!onSuccess) {
          toast("Product updated successfully.", { variant: "success" });
        }
        onEditSave?.(savedProduct as ProductWithImages);
        onSuccess?.();
        router.refresh();
      }
    } catch (error: unknown) {
      if (error instanceof Error) {
        setUploadError(error.message);
      } else {
        setUploadError("An unknown error occurred");
      }
    }
  };

  const submitHandler = useCallback(methods.handleSubmit(onSubmit), [methods, onSubmit]);

  return (
    <FormProvider {...methods}>
      <ProductFormContext.Provider
        value={{
          register,
          handleSubmit: submitHandler,
          errors,
          setValue,
          getValues,
          imageSlots,
          imageLinks,
          imageBase64s,
          uploading: createMutation.isPending || updateMutation.isPending,
          uploadError,
          uploadSuccess,
          showFileManager,
          setShowFileManager,
          handleSlotImageChange,
          handleSlotFileSelect,
          handleSlotDisconnectImage,
          handleMultiImageChange,
          handleMultiFileSelect,
          swapImageSlots,
          setImageLinkAt,
          setImageBase64At,
          setImagesReordering,
          catalogs,
          catalogsLoading,
          catalogsError,
          selectedCatalogIds,
          toggleCatalog,
          categories,
          categoriesLoading,
          selectedCategoryId,
          setCategoryId,
          tags,
          tagsLoading,
          selectedTagIds,
          toggleTag,
          producers,
          producersLoading,
          selectedProducerIds,
          toggleProducer,
          selectedNoteIds,
          toggleNote,
          removeNote,
          parameters,
          parametersLoading,
          parameterValues,
          addParameterValue: (): void =>
            setParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => [...prev, { parameterId: "", value: "" }]),
          updateParameterId: (index: number, parameterId: string): void =>
            setParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => {
              const next = [...prev];
              if (!next[index]) return prev;
              next[index] = { ...next[index], parameterId };
              return next;
            }),
          updateParameterValue: (index: number, value: string): void =>
            setParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => {
              const next = [...prev];
              if (!next[index]) return prev;
              next[index] = { ...next[index], value };
              return next;
            }),
          removeParameterValue: (index: number): void =>
            setParameterValues((prev: ProductParameterValue[]): ProductParameterValue[] => prev.filter((_: ProductParameterValue, i: number): boolean => i !== index)),
          filteredLanguages,
          filteredPriceGroups,
          generationError,
          setGenerationError,
          product,
        }}
      >
        {children}
      </ProductFormContext.Provider>
    </FormProvider>
  );
}

"use client";

import React from "react";
import {
  Brush,
  Check,
  Circle,
  Filter,
  Lasso,
  MousePointer2,
  Pentagon,
  RectangleHorizontal,
  RotateCcw,
  Sparkles,
  Trash2,
  Unlink,
} from "lucide-react";

import { Button, Tooltip } from "@/shared/ui";
import { cn } from "@/shared/utils";
import type { VectorToolMode } from "../types";

export type VectorDrawingToolbarVariant = "full" | "min";

export interface VectorDrawingToolbarProps {
  tool: VectorToolMode;
  onSelectTool: (tool: VectorToolMode) => void;
  onUndo?: (() => void) | undefined;
  onClose?: (() => void) | undefined;
  onDetach?: (() => void) | undefined;
  onClear?: (() => void) | undefined;
  onSmooth?: (() => void) | undefined;
  onSimplify?: (() => void) | undefined;
  disableUndo?: boolean | undefined;
  disableClose?: boolean | undefined;
  disableDetach?: boolean | undefined;
  disableClear?: boolean | undefined;
  disableSmooth?: boolean | undefined;
  disableSimplify?: boolean | undefined;
  className?: string | undefined;
  variant?: VectorDrawingToolbarVariant | undefined;
}

type ToolOption = {
  key: VectorToolMode;
  label: string;
  icon: React.ReactNode;
};

const FULL_TOOLS: ToolOption[] = [
  { key: "select", label: "Select", icon: <MousePointer2 className="size-4" /> },
  { key: "polygon", label: "Polygon", icon: <Pentagon className="size-4" /> },
  { key: "lasso", label: "Lasso", icon: <Lasso className="size-4" /> },
  { key: "rect", label: "Rectangle", icon: <RectangleHorizontal className="size-4" /> },
  { key: "ellipse", label: "Ellipse", icon: <Circle className="size-4" /> },
  { key: "brush", label: "Brush", icon: <Brush className="size-4" /> },
];

const MIN_TOOLS: ToolOption[] = [
  { key: "select", label: "Edit", icon: <MousePointer2 className="size-4" /> },
  { key: "polygon", label: "Pen", icon: <Pentagon className="size-4" /> },
];

export function VectorDrawingToolbar({
  tool,
  onSelectTool,
  onUndo,
  onClose,
  onDetach,
  onClear,
  onSmooth,
  onSimplify,
  disableUndo,
  disableClose,
  disableDetach,
  disableClear,
  disableSmooth,
  disableSimplify,
  className,
  variant = "full",
}: VectorDrawingToolbarProps): React.JSX.Element {
  const toolOptions = variant === "min" ? MIN_TOOLS : FULL_TOOLS;
  const hasActions = Boolean(onUndo || onClose || onDetach || onClear || onSmooth || onSimplify);

  return (
    <div
      className={cn(
        "flex items-center gap-2 rounded-full border border-border/60 bg-card/80 px-3 py-2 shadow-lg",
        className
      )}
    >
      {toolOptions.map((option: ToolOption) => (
        <Tooltip key={option.key} content={option.label}>
          <Button
            type="button"
            variant={tool === option.key ? "secondary" : "outline"}
            size="icon"
            onClick={() => onSelectTool(option.key)}
          >
            {option.icon}
          </Button>
        </Tooltip>
      ))}
      {hasActions ? <div className="mx-1 h-6 w-px bg-border" /> : null}
      {onUndo ? (
        <Tooltip content="Undo last point">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onUndo}
            disabled={disableUndo}
          >
            <RotateCcw className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
      {onClose ? (
        <Tooltip content="Close polygon">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onClose}
            disabled={disableClose}
          >
            <Check className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
      {onDetach ? (
        <Tooltip content="Detach polygon">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onDetach}
            disabled={disableDetach}
          >
            <Unlink className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
      {onClear ? (
        <Tooltip content="Clear shapes">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onClear}
            disabled={disableClear}
          >
            <Trash2 className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
      {onSmooth ? (
        <Tooltip content="Smooth path">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onSmooth}
            disabled={disableSmooth}
          >
            <Sparkles className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
      {onSimplify ? (
        <Tooltip content="Simplify path">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onSimplify}
            disabled={disableSimplify}
          >
            <Filter className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
    </div>
  );
}

import { useMutation, useQueryClient, type UseMutationResult, type QueryClient } from "@tanstack/react-query";
import { useCallback } from "react";
import { useToast } from "@/shared/ui";
import { logClientError } from "@/shared/utils/observability/client-error-logger";

interface QueuedMutation {
  id: string;
  mutationFn: () => Promise<unknown>;
  queryKey: readonly unknown[];
  optimisticUpdate?: ((oldData: unknown) => unknown) | undefined;
  invalidateKeys?: (readonly (readonly unknown[])[]) | undefined;
  onProcessed?: (() => void) | undefined;
  timestamp: number;
}

class OfflineMutationQueue {
  private queue: QueuedMutation[] = [];
  private isProcessing: boolean = false;

  add(mutation: QueuedMutation): void {
    this.queue.push(mutation);
    this.saveToStorage();
  }

  async processQueue(queryClient: QueryClient): Promise<void> {
    if (this.isProcessing || this.queue.length === 0) return;

    this.isProcessing = true;

    while (this.queue.length > 0) {
      const mutation = this.queue.shift();
      if (!mutation) break;

      try {
        await mutation.mutationFn();
        void queryClient.invalidateQueries({ queryKey: mutation.queryKey });
        if (mutation.invalidateKeys) {
          mutation.invalidateKeys.forEach((key: readonly unknown[]) => {
            void queryClient.invalidateQueries({ queryKey: key });
          });
        }
        mutation.onProcessed?.();
      } catch (error) {
        logClientError(error, { 
          context: { 
            source: 'offline-queue', 
            mutationId: mutation.id,
            queryKey: mutation.queryKey
          } 
        });
        // Re-queue if it's a network error
        if (error instanceof Error && error.message.includes('fetch')) {
          this.queue.unshift(mutation);
          break;
        }
      }
    }

    this.isProcessing = false;
    this.saveToStorage();
  }

  private saveToStorage(): void {
    if (typeof window !== 'undefined') {
      // NOTE: function serialization is not supported by JSON.stringify
      // In a real app, you'd store mutation metadata and reconstruct the fn
      const payload = this.queue.map(({ mutationFn: _, onProcessed: __, ...rest }: QueuedMutation) => rest);
      if (payload.length === 0) {
        localStorage.removeItem('offline-mutation-queue');
      } else {
        localStorage.setItem('offline-mutation-queue', JSON.stringify(payload));
      }
    }
  }

  loadFromStorage(): void {
    if (typeof window !== 'undefined') {
      const stored = localStorage.getItem('offline-mutation-queue');
      if (stored) {
        try {
          // We can't really restore the function from storage this way
          const parsed = JSON.parse(stored) as QueuedMutation[];
                      this.queue = parsed.filter((item: QueuedMutation): boolean => typeof item?.mutationFn === "function");        } catch {
          this.queue = [];
        }
      }
    }
  }

  clear(): void {
    this.queue = [];
    this.saveToStorage();
  }
}

const mutationQueue = new OfflineMutationQueue();

export function useOfflineMutation<TData, TError = Error, TVariables = void, TContext = unknown>(
  mutationFn: (variables: TVariables) => Promise<TData>,
  options: {
    queryKey: readonly unknown[];
    extraInvalidateKeys?: readonly (readonly unknown[])[] | ((variables: TVariables) => readonly (readonly unknown[])[]);
    optimisticUpdate?: (oldData: TContext | undefined, variables: TVariables) => TContext;
    successMessage?: string;
    errorMessage?: string;
    queuedMessage?: string;
    processedMessage?: string;
    onQueued?: (variables: TVariables) => void;
    onProcessed?: (variables: TVariables) => void;
  }
): UseMutationResult<TData, TError, TVariables, TContext> {
  const queryClient = useQueryClient();
  const { toast } = useToast();
  const resolveExtraKeys = useCallback(
    (variables: TVariables): readonly (readonly unknown[])[] => {
      if (!options.extraInvalidateKeys) return [];
      return typeof options.extraInvalidateKeys === "function"
        ? options.extraInvalidateKeys(variables)
        : options.extraInvalidateKeys;
    },
    [options.extraInvalidateKeys, options]
  );

  return useMutation({
    mutationFn: async (variables: TVariables): Promise<TData> => {
      const isOnline = typeof navigator === "undefined" ? true : navigator.onLine;
      if (!isOnline) {
        const extraKeys = resolveExtraKeys(variables);
        options.onQueued?.(variables);
        // Queue for later execution
        const queuedMutation: QueuedMutation = {
          id: Date.now().toString(),
          mutationFn: (): Promise<TData> => mutationFn(variables),
          queryKey: options.queryKey,
          invalidateKeys: extraKeys,
          onProcessed: (): void => {
            if (options.processedMessage) {
              toast(options.processedMessage, { variant: "success" });
            }
            options.onProcessed?.(variables);
          },
          timestamp: Date.now(),
        };

        mutationQueue.add(queuedMutation);

        // Apply optimistic update
        if (options.optimisticUpdate) {
          queryClient.setQueryData(options.queryKey, (old: TContext | undefined) => 
            options.optimisticUpdate!(old, variables)
          );
        }

        toast(options.queuedMessage || "Changes saved offline. Will sync when online.", { variant: "info" });
        return null as TData;
      }

      return mutationFn(variables);
    },
    onSuccess: (_data: TData, variables: TVariables): void => {
      const isOnline = typeof navigator === "undefined" ? true : navigator.onLine;
      if (isOnline && options.successMessage) {
        toast(options.successMessage, { variant: "success" });
      }
      if (!isOnline) return;
      void queryClient.invalidateQueries({ queryKey: options.queryKey });
      const extraKeys = resolveExtraKeys(variables);
      extraKeys.forEach((key: readonly unknown[]) => {
        void queryClient.invalidateQueries({ queryKey: key });
      });
    },
    onError: (error: TError): void => {
      const message = options.errorMessage || 
        (error instanceof Error ? error.message : "An error occurred");
      toast(message, { variant: "error" });
    },
  });
}

export interface OfflineSyncHookResult {
  processQueue: () => Promise<void>;
}

// Hook to process queued mutations when coming online
export function useOfflineSync(): OfflineSyncHookResult {
  const queryClient = useQueryClient();

  const processQueue = useCallback(async (): Promise<void> => {
    mutationQueue.loadFromStorage();
    await mutationQueue.processQueue(queryClient);
  }, [queryClient]);

  return { processQueue };
}

export function clearOfflineMutationQueue(): void {
  mutationQueue.clear();
}

