import "server-only";

import { LRUCache } from "lru-cache";

export type SettingRecord = { key: string; value: string };
export type SettingsScope = "all" | "light" | "heavy";

const SETTINGS_CACHE_TTL_MS = 120_000;
const SETTINGS_CACHE_STALE_TTL_MS = 10 * 60_000;
const settingsLru = new LRUCache<string, SettingRecord[]>({
  max: 5,
  ttl: SETTINGS_CACHE_TTL_MS,
  updateAgeOnGet: true,
});

let settingsCacheHits = 0;
let settingsCacheMisses = 0;
const settingsInflight = new Map<string, Promise<SettingRecord[]>>();
const lastKnownSettings = new Map<string, { data: SettingRecord[]; fetchedAt: number }>();

const normalizeScope = (scope?: SettingsScope | null): SettingsScope =>
  scope === "heavy" || scope === "light" || scope === "all" ? scope : "all";

const cacheKey = (scope?: SettingsScope | null): string =>
  `settings:${normalizeScope(scope)}`;

export const isSettingsCacheDebugEnabled = (): boolean =>
  process.env.NODE_ENV !== "production" || process.env.DEBUG_SETTINGS === "true";

interface SettingsCacheStats {
  size: number;
  ttlMs: number;
  staleTtlMs: number;
  hits: number;
  misses: number;
  inflight: string[];
  staleAgeMs: Record<string, number>;
}

export const getSettingsCacheStats = (): SettingsCacheStats => ({
  size: settingsLru.size,
  ttlMs: SETTINGS_CACHE_TTL_MS,
  staleTtlMs: SETTINGS_CACHE_STALE_TTL_MS,
  hits: settingsCacheHits,
  misses: settingsCacheMisses,
  inflight: Array.from(settingsInflight.keys()),
  staleAgeMs: Array.from(lastKnownSettings.entries()).reduce<Record<string, number>>(
    (acc: Record<string, number>, [scope, entry]) => {
      acc[scope] = Date.now() - entry.fetchedAt;
      return acc;
    },
    {}
  ),
});

export const getCachedSettings = (scope?: SettingsScope | null): SettingRecord[] | null => {
  const cached = settingsLru.get(cacheKey(scope));
  if (cached) {
    settingsCacheHits += 1;
    return cached;
  }
  settingsCacheMisses += 1;
  return null;
};

export const setCachedSettings = (settings: SettingRecord[], scope?: SettingsScope | null): void => {
  const key = cacheKey(scope);
  settingsLru.set(key, settings);
  lastKnownSettings.set(key, { data: settings, fetchedAt: Date.now() });
};

export const clearSettingsCache = (scope?: SettingsScope | null): void => {
  if (scope) {
    const key = cacheKey(scope);
    settingsLru.delete(key);
    lastKnownSettings.delete(key);
    settingsInflight.delete(key);
  } else {
    settingsLru.clear();
    lastKnownSettings.clear();
    settingsInflight.clear();
  }
  settingsCacheHits = 0;
  settingsCacheMisses = 0;
};

export const getSettingsInflight = (scope?: SettingsScope | null): Promise<SettingRecord[]> | null =>
  settingsInflight.get(cacheKey(scope)) ?? null;

export const setSettingsInflight = (
  inflight: Promise<SettingRecord[]> | null,
  scope?: SettingsScope | null
): void => {
  const key = cacheKey(scope);
  if (inflight) {
    settingsInflight.set(key, inflight);
  } else {
    settingsInflight.delete(key);
  }
};

export const getStaleSettings = (scope?: SettingsScope | null): SettingRecord[] | null => {
  const entry = lastKnownSettings.get(cacheKey(scope));
  if (!entry) return null;
  if (Date.now() - entry.fetchedAt > SETTINGS_CACHE_STALE_TTL_MS) return null;
  return entry.data;
};

"use client";
import React, { JSX, memo, useEffect, useMemo, useState } from "react";

import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "./table";
import { EmptyState } from "./empty-state";
import {
  ColumnDef,
  flexRender,
  getCoreRowModel,
  getFilteredRowModel,
  getSortedRowModel,
  SortingState,
  useReactTable,
  Table as ReactTable,
  RowSelectionState,
  OnChangeFn,
} from "@tanstack/react-table";
import { useQueryClient, QueryClient } from "@tanstack/react-query";


interface DataTableProps<TData> {
  columns: ColumnDef<TData>[];
  data: TData[];
  initialSorting?: SortingState;
  sortingStorageKey?: string;
  getRowId?: (row: TData) => string | number;
  footer?: (table: ReactTable<TData>) => React.ReactNode;
  rowSelection?: RowSelectionState;
  onRowSelectionChange?: OnChangeFn<RowSelectionState>;
  isLoading?: boolean;
  skeletonRows?: React.ReactNode;
  meta?: Record<string, unknown>;
}

declare module "@tanstack/react-table" {
  interface TableMeta<TData> {
    queryClient?: QueryClient;
  }
}

export const DataTable = memo(function DataTable<TData>({
  columns,
  data,
  initialSorting,
  sortingStorageKey,
  getRowId,
  footer,
  rowSelection: controlledRowSelection,
  onRowSelectionChange: controlledOnRowSelectionChange,
  isLoading = false,
  skeletonRows,
  meta,
}: DataTableProps<TData>) {
  const [internalRowSelection, setInternalRowSelection] = useState<RowSelectionState>({});
  const [sorting, setSorting] = useState<SortingState>(initialSorting ?? []);
  const queryClient = useQueryClient();

  const rowSelection = controlledRowSelection ?? internalRowSelection;
  const onRowSelectionChange = controlledOnRowSelectionChange ?? setInternalRowSelection;

  useEffect(() => {
    if (!sortingStorageKey) return;
    try {
      const raw = window.localStorage.getItem(sortingStorageKey);
      if (!raw) return;
      const parsed = JSON.parse(raw) as SortingState;
      if (Array.isArray(parsed)) {
        setSorting(parsed);
      }
    } catch {
      // Ignore invalid localStorage values.
    }
  }, [sortingStorageKey]);

  useEffect(() => {
    if (!sortingStorageKey) return;
    try {
      window.localStorage.setItem(sortingStorageKey, JSON.stringify(sorting));
    } catch {
      // Ignore storage write errors.
    }
  }, [sorting, sortingStorageKey]);

  // Memoize table meta to prevent unnecessary re-renders
  const tableMeta = useMemo(() => ({
    ...meta,
    queryClient,
  }), [
    meta,
    queryClient,
  ]);

  // TanStack Table is not compatible with React Compiler memoization warnings.
  // eslint-disable-next-line react-hooks/incompatible-library
  const table = useReactTable<TData>({
    data,
    columns,
    getRowId: getRowId as (row: TData) => string,
    getCoreRowModel: getCoreRowModel(),
    onRowSelectionChange: onRowSelectionChange,
    getFilteredRowModel: getFilteredRowModel(),
    getSortedRowModel: getSortedRowModel(),
    onSortingChange: setSorting,
    state: {
      rowSelection,
      sorting,
    },
    meta: tableMeta,
  });

  return (
    <div className="rounded-md border border-border">
      <Table>
        <TableHeader>
          {table.getHeaderGroups().map((headerGroup) => (
            <TableRow key={headerGroup.id} className="border-border">
              {headerGroup.headers.map((header) => {
                return (
                  <TableHead key={header.id} className="text-foreground">
                    {header.isPlaceholder
                      ? null
                      : flexRender(
                          header.column.columnDef.header,
                          header.getContext()
                        )}
                  </TableHead>
                );
              })}
            </TableRow>
          ))}
        </TableHeader>
        <TableBody>
          {isLoading ? (
            skeletonRows || (
              <TableRow>
                <TableCell
                  colSpan={columns.length}
                  className="h-24 text-center text-muted-foreground"
                >
                  Loading...
                </TableCell>
              </TableRow>
            )
          ) : table.getRowModel().rows?.length ? (
            table.getRowModel().rows.map((row) => (
              <TableRow
                key={row.id}
                data-state={row.getIsSelected() && "selected"}
                className="border-border"
                data-row-id={getRowId ? getRowId(row.original) : undefined}
              >
                {row.getVisibleCells().map((cell) => (
                  <TableCell key={cell.id} className="text-muted-foreground">
                    {flexRender(cell.column.columnDef.cell, cell.getContext())}
                  </TableCell>
                ))}
              </TableRow>
            ))
          ) : (
            <TableRow>
              <TableCell
                colSpan={columns.length}
                className="h-24 py-12"
              >
                <EmptyState 
                  title="No results" 
                  description="Try adjusting your filters to find what you're looking for."
                  className="border-none p-0"
                />
              </TableCell>
            </TableRow>
          )}
        </TableBody>
      </Table>
      {footer && footer(table)}
    </div>
  );
}) as <TData>(props: DataTableProps<TData>) => JSX.Element;

"use client"

import * as React from "react"
import * as SelectPrimitive from "@radix-ui/react-select"
import { Check, ChevronDown } from "lucide-react"
import { usePathname } from "next/navigation"

import { cn } from "@/shared/utils"

type NativeOption = { value: string; label: string; disabled?: boolean | undefined }

type NativeSelectContextValue = {
  value: string
  onValueChange?: ((value: string) => void) | undefined
  disabled?: boolean | undefined
  options: NativeOption[]
  placeholder?: string | undefined
}

const NativeSelectContext = React.createContext<NativeSelectContextValue | null>(null)

const useNativeSelectMode = (): boolean => {
  const pathname = usePathname()
  return pathname ? pathname.startsWith("/admin/image-studio") : false
}

const getNodeText = (node: React.ReactNode): string => {
  if (node === null || node === undefined || typeof node === "boolean") return ""
  if (typeof node === "string" || typeof node === "number") return String(node)
  if (Array.isArray(node)) return node.map(getNodeText).join("")
  if (React.isValidElement(node) && node.props && typeof node.props === "object" && "children" in node.props) {
    return getNodeText(node.props.children as React.ReactNode)
  }
  return ""
}

const extractNativeOptions = (children: React.ReactNode): { options: NativeOption[]; placeholder?: string | undefined } => {
  const options: NativeOption[] = []
  let placeholder: string | undefined

  const walk = (node: React.ReactNode): void => {
    if (!node) return
    React.Children.forEach(node, (child) => {
      if (!React.isValidElement(child)) return

      const props = child.props as Record<string, unknown>

      if (child.type === SelectValue && typeof props?.placeholder === "string") {
        placeholder = props.placeholder
      }
      if (child.type === SelectContent || child.type === SelectGroup) {
        walk(props.children as React.ReactNode)
        return
      }
      if (child.type === SelectItem) {
        const value = typeof props.value === "string" ? props.value : (typeof props.value === "number" ? String(props.value) : "")
        if (!value) return
        options.push({
          value,
          label: getNodeText(props.children as React.ReactNode),
          disabled: Boolean(props.disabled),
        })
        return
      }
      if (props.children) {
        walk(props.children as React.ReactNode)
      }
    })
  }

  walk(children)
  return { options, placeholder }
}

const Select: React.FC<
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.Root>
> = ({ value, defaultValue, onValueChange: onValueChangeProp, disabled, children, ...props }) => {
  const useNativeSelect = useNativeSelectMode()

  const { options, placeholder } = React.useMemo(() => 
    useNativeSelect ? extractNativeOptions(children) : { options: [], placeholder: undefined },
    [children, useNativeSelect]
  )

  const handleValueChange = React.useMemo(() => {
    if (typeof onValueChangeProp !== "function") return undefined
    return (val: string) => onValueChangeProp(val)
  }, [onValueChangeProp])

  if (!useNativeSelect) {
    return (
      <SelectPrimitive.Root
        {...(value !== undefined ? { value } : {})}
        {...(defaultValue !== undefined ? { defaultValue } : {})}
        {...(handleValueChange !== undefined ? { onValueChange: handleValueChange } : {})}
        {...(disabled !== undefined ? { disabled } : {})}
        {...props}
      >
        {children}
      </SelectPrimitive.Root>
    )
  }

  const normalizedValue = typeof value === "string" ? value : typeof defaultValue === "string" ? defaultValue : ""

  return (
    <NativeSelectContext.Provider
      value={{
        value: normalizedValue,
        onValueChange: handleValueChange,
        disabled: disabled !== undefined ? Boolean(disabled) : undefined,
        options,
        placeholder,
      }}
    >
      {children}
    </NativeSelectContext.Provider>
  )
}

const SelectGroup = (props: React.ComponentPropsWithoutRef<typeof SelectPrimitive.Group>) => {
  const useNativeSelect = useNativeSelectMode()
  if (!useNativeSelect) return <SelectPrimitive.Group {...props} />
  return <>{props.children}</>
}

const SelectValue = (props: React.ComponentPropsWithoutRef<typeof SelectPrimitive.Value>) => {
  const useNativeSelect = useNativeSelectMode()
  if (!useNativeSelect) return <SelectPrimitive.Value {...props} />
  return null
}

const SelectTrigger = React.forwardRef<
  React.ElementRef<typeof SelectPrimitive.Trigger>,
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.Trigger>
>(({ className, ...props }, ref) => {
  const useNativeSelect = useNativeSelectMode()
  const context = React.useContext(NativeSelectContext)

  if (!useNativeSelect) {
    return (
      <SelectPrimitive.Trigger
        ref={ref}
        className={cn(
          "flex h-10 w-full items-center justify-between rounded-md border border-foreground/10 bg-transparent px-3 py-2 text-sm transition-colors ring-offset-background placeholder:text-muted-foreground/70 focus:outline-none focus:ring-2 focus:ring-ring/40 focus:ring-offset-2 focus:border-foreground/30 hover:border-foreground/20 disabled:cursor-not-allowed disabled:opacity-50",
          className
        )}
        {...props}
      >
        {props.children}
        <SelectPrimitive.Icon asChild>
          <ChevronDown className="size-4 opacity-50" />
        </SelectPrimitive.Icon>
      </SelectPrimitive.Trigger>
    )
  }

  if (!context) {
    return (
      <select
        className={cn(
          "h-10 w-full rounded-md border border-foreground/10 bg-transparent px-3 py-2 text-sm text-foreground/90 focus:outline-none focus:ring-2 focus:ring-ring/40 focus:ring-offset-2 focus:border-foreground/30 disabled:cursor-not-allowed disabled:opacity-50",
          className
        )}
        disabled
      />
    )
  }

  const { value, onValueChange, disabled, options, placeholder } = context
  const hasValue = value !== ""

  return (
    <select
      className={cn(
        "h-10 w-full rounded-md border border-foreground/10 bg-transparent px-3 py-2 text-sm text-foreground/90 focus:outline-none focus:ring-2 focus:ring-ring/40 focus:ring-offset-2 focus:border-foreground/30 disabled:cursor-not-allowed disabled:opacity-50",
        className
      )}
      value={value}
      onChange={(event) => onValueChange?.(event.target.value)}
      disabled={disabled}
    >
      {placeholder ? (
        <option value="" disabled>
          {placeholder}
        </option>
      ) : null}
      {!hasValue && !placeholder ? (
        <option value="" disabled>
          Select an option
        </option>
      ) : null}
      {options.map((option) => (
        <option key={option.value} value={option.value} disabled={option.disabled}>
          {option.label || option.value}
        </option>
      ))}
    </select>
  )
})
SelectTrigger.displayName = SelectPrimitive.Trigger.displayName

const SelectContent = React.forwardRef<
  React.ElementRef<typeof SelectPrimitive.Content>,
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.Content>
>(({ className, children, position = "item-aligned", ...props }, ref) => {
  const useNativeSelect = useNativeSelectMode()
  if (useNativeSelect) return null
  return (
    <SelectPrimitive.Portal>
      <SelectPrimitive.Content
        ref={ref}
        className={cn(
          "relative z-50 min-w-[8rem] overflow-hidden rounded-md border border-border/50 bg-popover/90 text-popover-foreground shadow-lg backdrop-blur-md data-[state=open]:animate-in data-[state=closed]:animate-out data-[state=closed]:fade-out-0 data-[state=open]:fade-in-0 data-[state=closed]:zoom-out-95 data-[state=open]:zoom-in-95 data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2",
          position === "popper" &&
            "data-[side=bottom]:translate-y-1 data-[side=left]:-translate-x-1 data-[side=right]:translate-x-1 data-[side=top]:-translate-y-1",
          className
        )}
        position={position}
        {...props}
      >
        <SelectPrimitive.Viewport
          className={cn(
            "p-1",
            position === "popper" &&
              "h-[var(--radix-select-trigger-height)] w-full min-w-[var(--radix-select-trigger-width)]"
          )}
        >
          {children}
        </SelectPrimitive.Viewport>
      </SelectPrimitive.Content>
    </SelectPrimitive.Portal>
  )
})
SelectContent.displayName = SelectPrimitive.Content.displayName

const SelectLabel = React.forwardRef<
  React.ElementRef<typeof SelectPrimitive.Label>,
  React.ComponentPropsWithoutRef<typeof SelectPrimitive.Label>
